-- Scenario: 428 Birchwood Drive — VA Purchase Loan Appraisal
-- Category M2-S4-C5 #1 · difficulty 'basic'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 1,
  'basic',
  '428 Birchwood Drive — VA Purchase Loan Appraisal',
  'You are appraising a home at 428 Birchwood Drive, Anderson SC for a VA-insured purchase loan, on assignment from the Department of Veterans Affairs. Unlike conventional appraisals, VA appraisals are ordered by VA itself — not by the lender — to ensure independence from the transaction. The outcome is a Certificate of Reasonable Value (CRV), not a standard appraisal report. The veteran-buyer is purchasing the property at a contract price of $258,000, and the CRV will determine whether VA financing can proceed at that price. If the CRV value is below the contract price, the veteran may renegotiate the price, pay the difference in cash, or walk away without penalty. The appraiser must also confirm the property meets VA Minimum Property Requirements (MPRs); for this assignment, MPRs have been confirmed.

The subject is a 1,750 SF home built in 2000 with three bedrooms, two full bathrooms, and a 2-car garage, in good condition. Three closed sales within the past 3 months are provided — all qualify under VA''s 12-month comparable guideline. Two require GLA adjustments (one larger, one smaller than the subject) and one requires a bathroom adjustment. A teaching point at this level: both cost indications fall slightly BELOW the paired sales range — cost acts as a floor rather than a ceiling, the same relationship seen in Module 3 Basic. VA guidelines require the appraiser to explain this relationship, not just note it. Identify the differing features, derive market-supported adjustment values, apply them, and reconcile the adjusted prices into your CRV opinion of value.'
FROM scenario_categories WHERE code = 'M2-S4-C5';

