ded_helper": "Bracket toward Pairs 1 & 2; address Pair 3 explicitly."}, {"kind": "paired_dollar_diff", "feature_key": "bath", "title": "Bathroom Pairs — 2.5 vs. 3 Full Baths", "instruction": "Pairs isolate the bathroom count difference. Subtract the 2.5-bath sale price from the 3-full-bath sale price.", "input_label": "Your Price Difference", "input_suffix": "", "rows": [{"label": "1", "cells": ["$287,500", "$294,300"]}, {"label": "2", "cells": ["$292,000", "$298,900"]}], "column_headers": ["Pair", "2.5 Bath Sale", "3 Full Bath Sale"], "concluded_label": "Concluded Bathroom Adjustment", "concluded_helper": "Bracket your two results."}, {"kind": "paired_pct_per_month", "feature_key": "date", "title": "Market Conditions — Resale Pair Analysis", "instruction": "The same properties sold twice. For each pair, calculate the monthly appreciation rate using: (Resale − Original) ÷ Original ÷ Months × 100", "input_label": "Your %/Month", "input_suffix": "%/mo", "rows": [{"label": "A", "cells": ["$278,000", "$286,600", "10"]}, {"label": "B", "cells": ["$285,000", "$294,000", "9"]}, {"label": "C", "cells": ["$276,000", "$284,900", "11"]}], "column_headers": ["Property", "Original Sale Price", "Resale Price", "Months"], "concluded_label": "Concluded Monthly Rate", "concluded_helper": "Bracket your three results."}]}, {"key": "cost", "label": "Cost-Based Support", "intro": "GLA and bathroom have cost support. Both cost indications exceed the paired sales range — cost acts as a ceiling in both cases. Market Conditions has no applicable cost method. HUD 4000.1 requires presentation and explanation of cost support when available.", "items": [{"kind": "cost_calc", "feature_key": "gla", "title": "GLA Contributory Value ($/SF)", "fact_rows": [["RCN", "$79.00 / SF"], ["Effective Age", "18 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "18 ÷ 60 = 30%"], ["Formula", "$79.00 × (1 − 0.30) = ?"]], "input_suffix": "/SF"}, {"kind": "cost_calc", "feature_key": "bath", "title": "Bathroom Cost (Full Bath Addition)", "fact_rows": [["Cost to Add Full Bath", "$13,500"], ["Effective Age", "18 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "30%"], ["Formula", "$13,500 × (1 − 0.30) = ?"]], "input_suffix": ""}]}], "reconciliation": {"instruction": "Review both method indications and enter your reconciled adjustment for each item. Both GLA and bathroom cost exceed paired sales — weight paired sales in both cases. Market conditions reconciles directly from resale pairs.", "items": [{"feature_key": "gla", "label": "GLA Adjustment ($/SF)"}, {"feature_key": "bath", "label": "Bathroom Adjustment ($)"}, {"feature_key": "date", "label": "Market Conditions Adjustment (%/mo)"}]}}, "step3": {"instruction": "Apply your reconciled adjustments to each comparable. Use a NEGATIVE value where the comp is superior to the subject, and a POSITIVE value where it is inferior. Comps 1 and 2 each receive one negative adjustment. Comp 3 sold 8 months ago in an appreciating market and receives a positive market conditions adjustment. Formula: $283,000 × 8 months × your reconciled %/mo ÷ 100. HUD 4000.1 requires market-supported and documented adjustments throughout.", "applicable": {"C1": ["gla"], "C2": ["bath"], "C3": ["date"]}, "method_dropdown": ["Paired Sales Analysis", "Market Conditions (Resale Pairs)", "Cost-Based Support", "Grouped Paired Sales", "Regression Analysis", "Appraiser Judgment / Extraction"], "support_min_chars": 15}, "step4": {"show_net_gross_panel": false}}'::jsonb,
  '{"step1_correct_flags": {"C1": ["gla"], "C2": ["bath"], "C3": ["date"]}, "step1_rationale": "Comp 1 is 150 SF larger than the subject (superior GLA, single adjustment). Comp 2 has 3 full bathrooms versus the subject''s 2.5 (superior bath, single adjustment). Comp 3 sold 8 months ago in an appreciating market (inferior date, single adjustment). All other features (bedrooms, garage, year built, condition) are equivalent across all three comparables, and HUD Minimum Property Standards are met by all three.", "step2_tables": {"paired": {"gla": {"pair_answers": [46.0, 47.33, 58.67], "concluded_range": [46.0, 48.0], "rationale": "Pairs 1 and 2 cluster tightly at $46.00 and $47.33/SF — consistent market evidence. Pair 3 diverges significantly to $58.67/SF and must be excluded with documented reasoning per HUD 4000.1 (different submarket, anomalous transaction, or data anomaly). Bracket conclusion toward Pairs 1 & 2."}, "bath": {"pair_answers": [6800, 6900], "concluded_range": [6800, 6900], "rationale": "Two pairs bracket the half-bath/full-bath increment at $6,800 and $6,900 — tight market support."}, "date": {"pair_answers": [0.309, 0.351, 0.293], "concluded_range": [0.29, 0.36], "rationale": "Three resale pairs produce 0.31%, 0.35%, and 0.29%/mo. Bracket toward central tendency near 0.32%/mo, supported by the cluster of two pairs near the lower end."}}, "cost": {"gla": {"answer": 55.3, "rationale": "$79.00 × (1 − 0.30) = $55.30/SF. Significantly above the consistent paired sales range ($46.00–$47.33/SF) — clear ceiling. The market does not pay full depreciated replacement cost for additional GLA at this 2006 vintage. Weight paired sales; address the gap in the HUD addendum."}, "bath": {"answer": 9450, "rationale": "$13,500 × (1 − 0.30) = $9,450. Significantly exceeds paired sales of $6,800–$6,900. Clear ceiling — buyers pay less than cost to add a bathroom for this age. Weight paired sales."}}}, "step2_reconciliation": {"gla": {"range": [46.0, 48.0], "rationale": "Paired sales support $46.00–$47.33/SF (Pairs 1 & 2). Pair 3 ($58.67/SF) excluded with documented reasoning per HUD 4000.1. Cost support of $55.30/SF acts only as a ceiling — the gap warrants HUD addendum commentary that buyers consistently pay less than replacement cost for additional GLA. Reconcile near $47/SF."}, "bath": {"range": [6800, 6900], "rationale": "Paired sales bracket $6,800–$6,900. Cost ($9,450) significantly exceeds paired sales — clear ceiling. Weight paired sales; reconcile near $6,850."}, "date": {"range": [0.31, 0.33], "rationale": "Paired sales support a wider range of 0.29–0.35%/mo. No cost method applicable. Reconcile near central tendency at approximately 0.32%/mo."}}, "step3_adjustments": {"C1": {"gla": {"direction": "negative", "amount_per_unit": -47.0, "units": 150, "computed_amount": -7050, "method": "Paired Sales Analysis", "rationale": "Comp 1 is 150 SF larger than the subject (superior). At reconciled $47/SF (Pairs 1 & 2; Pair 3 outlier excluded per HUD 4000.1 documentation requirement), the GLA adjustment is −$7,050. Cost support of $55.30/SF acts only as a ceiling — buyers in this market pay roughly 85% of depreciated replacement cost for additional GLA at this vintage."}}, "C2": {"bath": {"direction": "negative", "amount": -6850, "method": "Paired Sales Analysis", "rationale": "Comp 2 has 3 full bathrooms versus the subject''s 2.5 (superior). The half-bath increment from two paired sales is approximately $6,850 (midpoint of $6,800–$6,900). Cost ($9,450) significantly exceeds paired sales — a clear ceiling. Buyers pay about 72% of replacement cost for bathroom additions in this market."}}, "C3": {"date": {"direction": "positive", "amount": 7245, "method": "Market Conditions (Resale Pairs)", "rationale": "Comp 3 sold 8 months ago in an appreciating market (inferior date). At reconciled 0.32%/mo: $283,000 × 8 × 0.32 ÷ 100 = $7,245. Three resale pairs support this rate, bringing Comp 3 in line with current market values for HUD review."}}}, "step4_adjusted_prices": {"C1": {"unadjusted": 309000, "adjusted": 301950}, "C2": {"unadjusted": 305000, "adjusted": 298150}, "C3": {"unadjusted": 283000, "adjusted": 290245}}, "step4_reconciliation_narrative": "Adjusted prices range from approximately $290,245 to $301,950 — a spread of about $11,700 across three comparables and three different adjustment types. The FHA appraised value is supported in the $295,000–$302,000 range, comfortably bracketing the $299,500 contract price. The FHA 203(b) context introduces a different government lending framework from the VA scenario. Where VA appraisals are ordered by the agency itself and result in a Certificate of Reasonable Value, FHA appraisals are ordered by the lender but performed by a Roster appraiser under HUD Handbook 4000.1 — a detailed compliance manual that governs both the property inspection (MPS) and the analytical requirements. The standard-level scenario introduces three analytical layers beyond the basic framework. First, the GLA outlier exclusion (Pair 3 at $58.67/SF vs. $46.00–$47.33 for Pairs 1 & 2) must be documented in the addendum — a HUD 4000.1 compliance requirement, not just good practice. Second, both cost indications act as ceilings — the appraiser must explain why market evidence governs over cost data. Third, the market conditions adjustment for Comp 3 — derived from current resale pairs — brings the older sale in line with current conditions. The case number remains active for 120 days; if the first transaction falls through, a second buyer may use the same appraisal.", "tolerance_note": "Student answers are accepted within ±5% of model derived values for paired-sales calculations and within the indicated reconciliation range. Step 3 adjustments accepted within ±13% of the computed amount for GLA, ±12% for fixed-amount features, and ±16% for market conditions."}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'adjustment_grid'
WHERE sc.code = 'M2-S4-C5'
  AND s.order_index = 2;

-- ─────────────────────────────────────────────────────
-- Scenario: 3892 Old Piedmont Highway — Eminent Domain / Just Compensation
-- Category M2-S4-C5 #3 · difficulty 'advanced'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 3,
  'advanced',
  '3892 Old Piedmont Highway — Eminent Domain / Just Compensation',
  'You are appraising a home at 3892 Old Piedmont Highway, Greenville SC for an eminent domain proceeding — a full taking by the South Carolina Department of Transportation (SCDOT) for the US-25 widening project. Just compensation is constitutionally guaranteed under the Fifth and Fourteenth Amendments and is defined as fair market value as of the date of taking — not value to the owner, not replacement cost, not investment value. There is no contract price; the appraisal opinion may be used in negotiation with SCDOT or presented in condemnation proceedings if the parties cannot reach agreement. Every analytical decision is potentially subject to challenge by SCDOT''s appraiser in a Daubert-style hearing.

The subject is a 2,350 SF home built in 2005 with three full bathrooms, a 2-car garage, in good condition, in a standard (non-amenitied) location. Three closed sales are provided, differing across four adjustment types: GLA, location, condition, and market conditions. The GLA paired sales include an outlier (Pair 4) that must be excluded with documented reasoning suitable for litigation. Comp 1 carries two simultaneous adjustments (GLA + Location, both negative). Comp 3 carries three simultaneous adjustments — GLA (positive), Location (negative, opposing direction), and Market Conditions (positive). Three of the four adjustment types lack cost support and rely entirely on market-derived paired sales. Identify the differing features, derive market-supported adjustments, apply them independently, and reconcile into your just compensation opinion. Comp 3''s gross adjustment burden must be addressed explicitly in the weighting commentary.'
FROM scenario_categories WHERE code = 'M2-S4-C5';

