["C1"], "diff_directions": {"C1": "superior"}}, {"label": "Bathrooms", "subject": "2 full", "comp_values": {"C1": "2 full", "C2": "2.5", "C3": "2 full"}, "feature_key": "bath", "diff_comps": ["C2"], "diff_directions": {"C2": "superior"}}, {"label": "Bedrooms", "subject": "3", "comp_values": {"C1": "3", "C2": "3", "C3": "3"}, "diff_comps": []}, {"label": "Garage", "subject": "2-car", "comp_values": {"C1": "2-car", "C2": "2-car", "C3": "2-car"}, "diff_comps": []}, {"label": "Year Built", "subject": "2012", "comp_values": {"C1": "2012", "C2": "2013", "C3": "2011"}, "diff_comps": []}, {"label": "Condition", "subject": "Good", "comp_values": {"C1": "Good", "C2": "Good", "C3": "Good"}, "diff_comps": []}, {"label": "Lake Access", "subject": "Deeded Community", "comp_values": {"C1": "Deeded Community", "C2": "Deeded Community", "C3": "None"}, "feature_key": "lake", "diff_comps": ["C3"], "diff_directions": {"C3": "inferior"}}], "step2": {"tabs": [{"key": "paired", "label": "Paired Sales Analysis", "intro": "Use the supporting market data to derive contributory values. Three tables: GLA, bathroom, and lake access. All pairs confirmed from Lake Keowee deeded-access communities.", "tables": [{"kind": "paired_dollar_per_unit", "feature_key": "gla", "title": "GLA Pairs — Calculate $/SF", "instruction": "All pairs confirmed from Lake Keowee deeded-access communities. Divide Price Difference ÷ SF Difference. Pairs are consistent and well-supported.", "input_label": "Your $/SF", "input_suffix": "/SF", "rows": [{"label": "1", "cells": ["1,770 SF / $319,000", "1,920 SF / $325,950", "150 SF", "$6,950"]}, {"label": "2", "cells": ["1,820 SF / $325,000", "1,970 SF / $332,050", "150 SF", "$7,050"]}, {"label": "3", "cells": ["1,860 SF / $330,000", "2,010 SF / $337,200", "150 SF", "$7,200"]}], "column_headers": ["Pair", "Sale A (SF / Price)", "Sale B (SF / Price)", "SF Diff", "Price Diff"], "concluded_label": "Concluded GLA Adjustment", "concluded_helper": "Bracket your three results — pairs cluster tightly."}, {"kind": "paired_dollar_diff", "feature_key": "bath", "title": "Bathroom Pairs — 2 Full vs. 2.5 Baths", "instruction": "Pairs isolate the bathroom count difference. Subtract the 2-full-bath sale price from the 2.5-bath sale price.", "input_label": "Your Price Difference", "input_suffix": "", "rows": [{"label": "1", "cells": ["$328,000", "$334,500"]}, {"label": "2", "cells": ["$333,500", "$340,200"]}], "column_headers": ["Pair", "2 Full Bath Sale", "2.5 Bath Sale"], "concluded_label": "Concluded Bathroom Adjustment", "concluded_helper": "Bracket your two results."}, {"kind": "paired_dollar_diff", "feature_key": "lake", "title": "Lake Access Pairs — None vs. Deeded Community", "instruction": "Pairs isolate the lake access difference. All from the Lake Keowee submarket. Subtract the no-access sale price from the deeded-access sale price. No cost method applicable — paired sales only.", "input_label": "Your Price Difference", "input_suffix": "", "rows": [{"label": "1", "cells": ["$302,000", "$320,000"]}, {"label": "2", "cells": ["$295,500", "$313,000"]}], "column_headers": ["Pair", "No Access Sale", "Deeded Access Sale"], "concluded_label": "Concluded Lake Access Adjustment", "concluded_helper": "Bracket your two results. No cost method — paired sales only."}]}, {"key": "cost", "label": "Cost-Based Support", "intro": "GLA and bathroom have cost support. In lake-area markets, cost for GLA is often a very high ceiling — land value and lake access drive total value well above the sum of land plus improvements. No cost method applies to lake access.", "items": [{"kind": "cost_calc", "feature_key": "gla", "title": "GLA Contributory Value ($/SF)", "fact_rows": [["RCN", "$81.00 / SF"], ["Effective Age", "12 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "12 ÷ 60 = 20%"], ["Formula", "$81.00 × (1 − 0.20) = ?"]], "input_suffix": "/SF"}, {"kind": "cost_calc", "feature_key": "bath", "title": "Bathroom Cost (Half-Bath Addition)", "fact_rows": [["Cost to Add Half Bath", "$10,500"], ["Effective Age", "12 years"], ["Economic Life", "60 years"], ["Depreciation Rate", "20%"], ["Formula", "$10,500 × (1 − 0.20) = ?"]], "input_suffix": ""}]}], "reconciliation": {"instruction": "Review both method indications and enter your reconciled adjustment for each item. GLA cost is a high ceiling; bathroom cost is a moderate ceiling — weight paired sales in both cases. Lake access reconciles directly from paired sales only — there is no cost method to cross-check.", "items": [{"feature_key": "gla", "label": "GLA Adjustment ($/SF)"}, {"feature_key": "bath", "label": "Bathroom Adjustment ($)"}, {"feature_key": "lake", "label": "Lake Access Adjustment ($)"}]}}, "step3": {"instruction": "Apply your reconciled adjustments to each comparable. Use a NEGATIVE value where the comp is superior to the subject, and a POSITIVE value where it is inferior. Comp 1 receives a negative GLA adjustment. Comp 2 receives a negative bathroom adjustment. Comp 3 receives a positive lake access adjustment (it has no lake access while the subject has deeded community access). Each rationale should cite the specific paired sales evidence used and confirm that lake access pairs are from the Lake Keowee deeded-access submarket.", "applicable": {"C1": ["gla"], "C2": ["bath"], "C3": ["lake"]}, "method_dropdown": ["Paired Sales Analysis", "Grouped Paired Sales", "Cost-Based Support", "Location / Amenity Paired Sales", "Regression Analysis", "Appraiser Judgment / Extraction"], "support_min_chars": 15}, "step4": {"show_net_gross_panel": false}}'::jsonb,
  '{"step1_correct_flags": {"C1": ["gla"], "C2": ["bath"], "C3": ["lake"]}, "step1_rationale": "Comp 1 is 150 SF larger than the subject (superior GLA, single negative adjustment). Comp 2 has 2.5 bathrooms versus the subject''s 2 full (superior bath, single negative adjustment). Comp 3 has no lake access while the subject has deeded community access to Lake Keowee (inferior, single positive adjustment). All other features (bedrooms, garage, year built, condition) are equivalent across all three comparables. Sale dates fall within 3 months — no market conditions adjustment required.", "step2_tables": {"paired": {"gla": {"pair_answers": [46.33, 47.0, 48.0], "concluded_range": [46.33, 48.0], "rationale": "Three pairs from Lake Keowee deeded-access communities produce $46.33, $47.00, and $48.00/SF — a tight $1.67 spread that constitutes strong, consistent market support."}, "bath": {"pair_answers": [6500, 6700], "concluded_range": [6500, 6700], "rationale": "Two pairs bracket the half-bath increment at $6,500 and $6,700 — tight market support."}, "lake": {"pair_answers": [18000, 17500], "concluded_range": [17500, 18000], "rationale": "Two pairs from the Lake Keowee submarket bracket the deeded-access premium at $17,500 and $18,000 — consistent market support. No cost method applicable; paired sales are the sole valid support method for this specialty feature."}}, "cost": {"gla": {"answer": 64.8, "rationale": "$81.00 × (1 − 0.20) = $64.80/SF. Significantly above the consistent paired sales range of $46.33–$48.00/SF — a high ceiling, characteristic of lake-area markets where land and location premiums dominate total value. Weight paired sales strongly."}, "bath": {"answer": 8400, "rationale": "$10,500 × (1 − 0.20) = $8,400. Exceeds paired sales of $6,500–$6,700 — a moderate ceiling. Market does not pay full replacement cost for bathroom additions at this 2012 vintage. Weight paired sales."}}}, "step2_reconciliation": {"gla": {"range": [47.0, 48.0], "rationale": "Paired sales support $46.33–$48.00/SF (three tightly clustered pairs from the Lake Keowee deeded-access submarket). Cost support of $64.80/SF is a high ceiling — land and lake access premiums drive value above the sum of land plus improvements. Reconcile near $47.50/SF."}, "bath": {"range": [6500, 6700], "rationale": "Paired sales bracket $6,500–$6,700. Cost support of $8,400 sits above — moderate ceiling. Reconcile within the paired bracket near $6,600."}, "lake": {"range": [17500, 18000], "rationale": "Paired sales bracket $17,500–$18,000 from the Lake Keowee deeded-access submarket only. No cost method applicable — lake access is a location characteristic and cannot be replicated through construction. Reconcile near $17,750."}}, "step3_adjustments": {"C1": {"gla": {"direction": "negative", "amount_per_unit": -47.5, "units": 150, "computed_amount": -7125, "method": "Paired Sales Analysis", "rationale": "Comp 1 is 150 SF larger than the subject (superior). At reconciled $47.50/SF (drawn from three Lake Keowee deeded-access pairs), the GLA adjustment is −$7,125. Cost support of $64.80/SF acts as a high ceiling, characteristic of lake-area markets — buyers do not pay replacement cost for additional GLA when land and lake access drive total value."}}, "C2": {"bath": {"direction": "negative", "amount": -6600, "method": "Paired Sales Analysis", "rationale": "Comp 2 has 2.5 bathrooms versus the subject''s 2 full (superior). The half-bath increment from two paired sales is approximately $6,600 (midpoint of $6,500–$6,700). Cost support of $8,400 acts as a moderate ceiling."}}, "C3": {"lake": {"direction": "positive", "amount": 17750, "method": "Location / Amenity Paired Sales", "rationale": "Comp 3 has no lake access while the subject has deeded community access to Lake Keowee (inferior). The lake access premium derived from two Lake Keowee submarket pairs is approximately $17,750 (midpoint of $17,500–$18,000). No cost method applicable for lake access — the Lake Keowee deeded-access submarket is the only valid source of comparable evidence."}}}, "step4_adjusted_prices": {"C1": {"unadjusted": 352000, "adjusted": 344875}, "C2": {"unadjusted": 348500, "adjusted": 341900}, "C3": {"unadjusted": 322000, "adjusted": 339750}}, "step4_reconciliation_narrative": "Adjusted prices cluster in a tight band of approximately $339,750–$344,875 — a spread of roughly $5,000. The opinion of market value is well-supported in the $340,000–$345,000 range, comfortably bracketing and supporting the $342,000 contract price. Lake-area markets introduce two specialty competencies not present in standard residential appraisal. First, comparable selection must account for market stratification by access tier — direct lakefront, deeded community access, and no access are three distinct submarkets, not a single market with an adjustment. Using a direct lakefront comparable to support a deeded-access appraisal without adjustment would overstate value; using a non-access comparable without adjustment would understate it. Second, the lake access adjustment has no cost method — you cannot build a lake, so depreciated replacement cost is meaningless for this feature. Paired sales from the same lake and the same access tier are the only valid support. The cost-vs-market gap for GLA ($64.80/SF cost vs. $47.50/SF market) is striking and characteristic of lake-area markets, where land and location premiums dominate total value. Future appraisers on this property should have demonstrated knowledge of the Lake Keowee deeded-access market segment.", "tolerance_note": "Student answers are accepted within ±5% of model derived values for paired-sales calculations and within the indicated reconciliation range. Step 3 adjustments accepted within ±13% of the computed amount for GLA, ±12% for fixed-amount features, and ±16% for market conditions."}'::jsonb
FROM scenarios s
JOIN scenario_categories sc ON sc.id = s.category_id
JOIN module_sections ms ON ms.id = sc.section_id
JOIN section_fields f ON f.section_id = ms.id AND f.field_key = 'adjustment_grid'
WHERE sc.code = 'M2-S4-C6'
  AND s.order_index = 1;

-- ─────────────────────────────────────────────────────
-- Scenario: 1224 Sunridge Drive — Owned Solar PV System Appraisal
-- Category M2-S4-C6 #2 · difficulty 'intermediate'
-- ─────────────────────────────────────────────────────
INSERT INTO scenarios
  (category_id, order_index, difficulty, title, scenario_text)
SELECT id, 2,
  'intermediate',
  '1224 Sunridge Drive — Owned Solar PV System Appraisal',
  'You are appraising a home at 1224 Sunridge Drive, Simpsonville SC for a purchase loan, on referral from Upstate Solar Realty Lending. Contract price is $348,000. The subject property includes an 8.2 kW owned rooftop photovoltaic (PV) system installed in 2018. Ownership status is critical to the analysis: owned panels may have positive contributory value supported by paired sales; leased panels typically contribute $0 or a negative adjustment (the buyer inherits lease payments). This system is owned free and clear and conveys with the property. Per Fannie Mae SEL-2019-07 and supporting market research, the depreciated cost of PV equipment consistently and significantly overstates its market contribution; cost is not an appropriate sole support method for the solar adjustment.

The subject is a 2,080 SF home built in 2014 with three bedrooms, 2.5 bathrooms, and a 2-car garage, in good condition. Three closed sales are provided. They differ from the subject across three adjustment types: GLA, solar PV, and market conditions (one comparable sold 9 months ago). At standard level, two analytical challenges are introduced. First, the GLA paired sales include a divergent Pair 3 — and notably, the Pair 3 outlier value is nearly identical to the GLA cost indication, suggesting cost-influenced pricing rather than typical market behavior. Second, the solar paired sales must come from confirmed owned-panel properties. Identify the differing features, derive market-supported adjustment values, apply them, and reconcile the adjusted prices into your opinion of market value.'
FROM scenario_categories WHERE code = 'M2-S4-C6';

